package com.bank.ea.domain;
import jakarta.persistence.*; import jakarta.validation.constraints.NotBlank; import java.time.Instant;
@Entity @Table(name="catalog_items") public class CatalogItem {
 public enum Type { APPLICATION, TECHNOLOGY, REVIEW, RISK, API } public enum Status { DRAFT, ACTIVE, UNDER_REVIEW, APPROVED, RESTRICTED, DEPRECATED, REJECTED, RETIRED }
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.EAGER) private Project project; @Transient private Long projectId; @Enumerated(EnumType.STRING) @Column(nullable=false) private Type type; @NotBlank @Column(nullable=false) private String name; @Column(length=2000) private String description; private String owner; @Enumerated(EnumType.STRING) @Column(nullable=false) private Status status=Status.DRAFT; private String criticality; private String classification; private String targetDate; @Column(nullable=false,updatable=false) private Instant createdAt=Instant.now(); @Column(nullable=false) private Instant updatedAt=Instant.now(); @PreUpdate void updated(){updatedAt=Instant.now();}
 public Long getId(){return id;} public void setId(Long v){id=v;} public Project getProject(){return project;} public void setProject(Project v){project=v;} public Long getProjectId(){return projectId!=null?projectId:(project==null?null:project.getId());} public void setProjectId(Long v){projectId=v;} public Type getType(){return type;} public void setType(Type v){type=v;} public String getName(){return name;} public void setName(String v){name=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public String getOwner(){return owner;} public void setOwner(String v){owner=v;} public Status getStatus(){return status;} public void setStatus(Status v){status=v;} public String getCriticality(){return criticality;} public void setCriticality(String v){criticality=v;} public String getClassification(){return classification;} public void setClassification(String v){classification=v;} public String getTargetDate(){return targetDate;} public void setTargetDate(String v){targetDate=v;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;}
}
